from __future__ import annotations
from dataclasses import dataclass, field
from typing import Any, Callable

@dataclass
class ToolDef:
    name: str
    description: str
    input_schema: dict[str, Any]   # JSON Schema for the tool's parameters
    handler: Callable[..., Any]    # the function that executes the tool
    tags: list[str] = field(default_factory=list)  # e.g. ["read", "crm", "billing"]

    def to_api_schema(self) -> dict[str, Any]:
        """Return the dict to include in the tools= list sent to the model."""
        return {
            "name": self.name,
            "description": self.description,
            "input_schema": self.input_schema,
        }

class ToolRegistry:
    def __init__(self) -> None:
        self._tools: dict[str, ToolDef] = {}

    def register(self, tool: ToolDef) -> None:
        if tool.name in self._tools:
            raise ValueError(f"Tool '{tool.name}' is already registered")
        self._tools[tool.name] = tool

    def unregister(self, name: str) -> None:
        self._tools.pop(name, None)

    def get(self, name: str) -> ToolDef | None:
        return self._tools.get(name)

    def list_all(self) -> list[ToolDef]:
        return list(self._tools.values())

    def search(self, query: str) -> list[ToolDef]:
        """Simple substring match against name, description, and tags."""
        q = query.lower()
        return [
            t for t in self._tools.values()
            if q in t.name.lower()
            or q in t.description.lower()
            or any(q in tag for tag in t.tags)
        ]

    def filter_by_tags(self, *tags: str) -> list[ToolDef]:
        """Return tools that have ALL of the given tags."""
        tag_set = set(tags)
        return [t for t in self._tools.values() if tag_set.issubset(set(t.tags))]

from mytools.registry import ToolRegistry, ToolDef

registry = ToolRegistry()

def tool(name: str, description: str, schema: dict, tags: list[str] | None = None):
    """Decorator that registers a function as a tool."""
    def decorator(fn):
        registry.register(ToolDef(
            name=name,
            description=description,
            input_schema=schema,
            handler=fn,
            tags=tags or [],
        ))
        return fn
    return decorator

