from anthropic import Anthropic

client = Anthropic()

def run_agent(user_message: str, user_role: str) -> str:
    # Select tools based on role
    if user_role == "read_only":
        active_tools = registry.filter_by_tags("read")
    elif user_role == "support":
        active_tools = registry.filter_by_tags("crm")  # read + write CRM, no billing
    elif user_role == "admin":
        active_tools = registry.list_all()
    else:
        active_tools = []

    tools_for_api = [t.to_api_schema() for t in active_tools]
    messages = [{"role": "user", "content": user_message}]

    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools_for_api,
            messages=messages,
        )
        if resp.stop_reason != "tool_use":
            return resp.content[0].text

        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            tool_def = registry.get(block.name)
            if tool_def is None:
                result = {"error": "NOT_FOUND",
                          "message": f"Tool '{block.name}' not available"}
            else:
                result = tool_def.handler(**block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": json.dumps(result),
            })
        messages.append({"role": "user", "content": tool_results})
